<template>
  <div id="app">
    <header class="site-header">
      <div class="header-inner">
        <div class="brand" @click="$router.push('/')">
          <span class="brand-title">案例分享示例</span>
          <span class="brand-sub">Personal Front-end Demo Lab</span>
        </div>

        <!-- PC：横向菜单 -->
        <el-menu
          v-show="!isMobile"
          :default-active="activeIndex"
          mode="horizontal"
          router
          class="nav-menu nav-menu--desktop"
        >
          <el-menu-item
            v-for="item in navItems"
            :key="item.path"
            :index="item.path"
          >
            {{ item.title }}
          </el-menu-item>
        </el-menu>

        <!-- 移动端：Dropdown 菜单 -->
        <el-dropdown
          v-show="isMobile"
          trigger="click"
          class="nav-menu nav-menu--mobile"
          @command="handleNavCommand"
        >
          <el-button type="primary" plain size="small" class="mobile-nav-trigger">
            {{ currentNavTitle }}
            <i class="el-icon-arrow-down el-icon--right"></i>
          </el-button>
          <el-dropdown-menu slot="dropdown" class="mobile-nav-dropdown">
            <el-dropdown-item
              v-for="item in navItems"
              :key="item.path"
              :command="item.path"
              :class="{ 'mobile-nav-item--active': item.path === activeIndex }"
            >
              <i
                class="mobile-nav-check"
                :class="item.path === activeIndex ? 'el-icon-check' : ''"
              ></i>
              {{ item.title }}
            </el-dropdown-item>
          </el-dropdown-menu>
        </el-dropdown>
      </div>
    </header>

    <main class="main-content">
      <router-view />
    </main>
  </div>
</template>

<script>
const NAV_ITEMS = [
  { path: '/', title: '分块拼图' },
  { path: '/canvas-annotate', title: 'Canvas 标注' },
  { path: '/scatter-perf', title: '散点图对比' },
  { path: '/component-showcase', title: '组件封装' }
]

const MOBILE_BREAKPOINT = 768

export default {
  name: 'App',
  data () {
    return {
      navItems: NAV_ITEMS,
      isMobile: false
    }
  },
  computed: {
    activeIndex () {
      return this.$route.path
    },
    currentNavTitle () {
      const item = this.navItems.find((i) => i.path === this.activeIndex)
      return item ? item.title : '菜单'
    }
  },
  mounted () {
    this.updateMobile()
    window.addEventListener('resize', this.updateMobile)
  },
  beforeDestroy () {
    window.removeEventListener('resize', this.updateMobile)
  },
  methods: {
    updateMobile () {
      this.isMobile = window.innerWidth < MOBILE_BREAKPOINT
    },
    handleNavCommand (path) {
      if (path && path !== this.$route.path) {
        this.$router.push(path)
      }
    }
  }
}
</script>

<style>
* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

html,
body,
#app {
  height: 100%;
}

body {
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', 'PingFang SC', 'Microsoft YaHei', sans-serif;
  background: #f0f2f5;
  color: #303133;
}

#app {
  display: flex;
  flex-direction: column;
  min-height: 100vh;
}

.site-header {
  flex-shrink: 0;
  background: #fff;
  border-bottom: 1px solid #e8eaed;
  box-shadow: 0 1px 4px rgba(0, 0, 0, 0.04);
}

.header-inner {
  max-width: 1440px;
  margin: 0 auto;
  padding: 0 24px;
  height: 56px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 16px;
}

.brand {
  cursor: pointer;
  user-select: none;
  flex-shrink: 1;
  min-width: 0;
}

.brand-title {
  display: block;
  font-size: 17px;
  font-weight: 600;
  color: #1f2d3d;
  line-height: 1.3;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.brand-sub {
  display: block;
  font-size: 11px;
  color: #909399;
  letter-spacing: 0.02em;
}

.nav-menu--desktop {
  flex: 1;
  display: flex;
  justify-content: flex-end;
  border-bottom: none !important;
  background: transparent !important;
}

.nav-menu--desktop.el-menu--horizontal > .el-menu-item {
  height: 56px;
  line-height: 56px;
  border-bottom: 2px solid transparent;
  color: #606266;
  font-size: 14px;
  padding: 0 18px;
}

.nav-menu--desktop.el-menu--horizontal > .el-menu-item:hover {
  background: transparent !important;
  color: #409eff;
}

.nav-menu--desktop.el-menu--horizontal > .el-menu-item.is-active {
  border-bottom-color: #409eff;
  color: #409eff;
  background: transparent !important;
}

.nav-menu--mobile {
  flex-shrink: 0;
}

.mobile-nav-trigger {
  max-width: 160px;
  overflow: hidden;
  text-overflow: ellipsis;
}

.mobile-nav-check {
  display: inline-block;
  width: 14px;
  margin-right: 4px;
  font-size: 12px;
  color: #409eff;
}

.mobile-nav-item--active {
  color: #409eff;
  font-weight: 600;
}

.main-content {
  flex: 1;
  min-height: 0;
  overflow: hidden;
  padding: 16px 24px 12px;
  max-width: 1440px;
  width: 100%;
  margin: 0 auto;
}

.site-footer {
  flex-shrink: 0;
  text-align: center;
  padding: 10px 16px;
  font-size: 12px;
  color: #909399;
  background: #fafafa;
  border-top: 1px solid #ebeef5;
}

@media (max-width: 767px) {
  .header-inner {
    padding: 0 12px;
    height: 52px;
  }

  .brand-title {
    font-size: 15px;
  }

  .brand-sub {
    display: none;
  }

  .main-content {
    padding: 12px 12px 8px;
  }

  .site-footer {
    font-size: 11px;
    padding: 8px 12px;
  }
}
</style>
