import Vue from 'vue'
import ElementUI, { Image, MenuItem, Submenu } from 'element-ui'
import 'element-ui/lib/theme-chalk/index.css'
import '@/assets/styles/global.css'
import { applyElementUiPatches } from '@/utils/elementUiPatches'
import App from './App.vue'
import router from './router'
import store from './store'

const CanvasSelect = require('@/utils/canvas-select.min.js')
window.CanvasSelect = CanvasSelect

applyElementUiPatches({ Image, MenuItem, Submenu })
Vue.use(ElementUI)

Vue.config.productionTip = false

new Vue({
  router,
  store,
  render: h => h(App)
}).$mount('#app')
