/**
 * Element UI 组件补丁（参考 uniqhs-ui main.js 202-279 行）
 * - el-menu：垂直菜单每级缩进 8px
 * - el-image 预览扩展：fullMode / noInfinite / viewerRotate（非 Element UI 原生 prop，走 $attrs）
 *
 * 模板写法必须与 $attrs 键名一致（camelCase）：
 *   fullMode | noInfinite | :viewerRotate="180"
 * 勿写 viewer-rotate / full-mode / no-infinite，补丁读取不到。
 */

const PATCH_ATTRS = {
  fullMode: {
    wrong: ['full-mode', 'fullmode'],
    example: 'fullMode'
  },
  noInfinite: {
    wrong: ['no-infinite', 'noinfinite'],
    example: 'noInfinite'
  },
  viewerRotate: {
    wrong: ['viewer-rotate', 'viewerrotate'],
    example: ':viewerRotate="180"'
  }
}

export function applyElementUiPatches ({ Image, MenuItem, Submenu }) {
  if (!Image || !MenuItem || !Submenu) {
    console.warn('[elementUiPatches] 缺少 Image / MenuItem / Submenu，跳过补丁')
    return
  }

  patchElImageAttrsHint(Image)

  window.ImageViewerHookMountedSetFullMode = function (vm) {
    vm.$nextTick(() => {
      const imgRef = vm.$refs.img && vm.$refs.img[0]
      if (!imgRef) return
      const { clientWidth, clientHeight } = document.body
      const imgW = imgRef.clientWidth
      const imgH = imgRef.clientHeight
      if (!imgW || !imgH) return
      let scale
      if (imgH / imgW > clientHeight / clientWidth) {
        scale = clientHeight / imgH
      } else {
        scale = clientWidth / imgW
      }
      vm.transform.scale = scale
    })
  }

  const ImageViewer = Image.components.ImageViewer
  if (!ImageViewer) return

  const origCreated = ImageViewer.created
  ImageViewer.created = function imageViewerCreatedPatched () {
    if (origCreated) {
      origCreated.call(this)
    }
    this.$on('hook:mounted', () => {
      const attrs = getImageParentAttrs(this)
      warnWrongPatchAttrs(attrs, 'ImageViewer')
      if (hasPatchAttr(attrs, 'fullMode')) {
        window.ImageViewerHookMountedSetFullMode(this)
      }
      if (hasPatchAttr(attrs, 'noInfinite')) {
        this.infinite = false
      }
      const rotate = getViewerRotate(attrs)
      if (rotate !== null) {
        this.transform.deg = rotate
      }
    })
  }

  const origReset = ImageViewer.methods.reset
  ImageViewer.methods.reset = function imageViewerResetPatched () {
    const attrs = getImageParentAttrs(this)
    const rotate = getViewerRotate(attrs)
    const useFull = hasPatchAttr(attrs, 'fullMode')
    if (rotate === null && !useFull) {
      if (origReset) origReset.call(this)
      return
    }
    this.transform = {
      scale: 1,
      deg: rotate !== null ? rotate : 0,
      offsetX: 0,
      offsetY: 0,
      enableTransition: false
    }
    if (useFull) {
      window.ImageViewerHookMountedSetFullMode(this)
    }
  }

  ;[MenuItem, Submenu].forEach((Component) => {
    if (!Component.mixins) {
      Component.mixins = []
    }
    Component.mixins.push({
      computed: {
        paddingStyle () {
          if (this.rootMenu.mode !== 'vertical') return {}
          const basePadding = 8
          let padding = basePadding
          let parent = this.$parent
          if (this.rootMenu.collapse) {
            padding = basePadding
          } else {
            while (parent && parent.$options.componentName !== 'ElMenu') {
              if (parent.$options.componentName === 'ElSubmenu') {
                padding += basePadding
              }
              parent = parent.$parent
            }
          }
          return { paddingLeft: padding + 'px' }
        }
      }
    })
  })
}

function patchElImageAttrsHint (Image) {
  if (!Image.mixins) Image.mixins = []
  Image.mixins.push({
    mounted () {
      warnWrongPatchAttrs(this.$attrs, 'el-image')
    }
  })
}

function getImageParentAttrs (viewerVm) {
  const parent = viewerVm.$parent
  return parent && parent.$attrs ? parent.$attrs : {}
}

function hasAttr (attrs, key) {
  return Object.prototype.hasOwnProperty.call(attrs, key)
}

/** 仅识别 camelCase 键名 */
function hasPatchAttr (attrs, key) {
  return hasAttr(attrs, key)
}

function getViewerRotate (attrs) {
  if (!hasPatchAttr(attrs, 'viewerRotate')) return null
  const val = attrs.viewerRotate
  if (val === '' || val === true) return 0
  const num = Number(val)
  return isFinite(num) ? num : 0
}

const warnedKeys = new Set()

function warnWrongPatchAttrs (attrs, source) {
  if (!attrs) return
  Object.keys(PATCH_ATTRS).forEach((camelKey) => {
    const { wrong, example } = PATCH_ATTRS[camelKey]
    wrong.forEach((badKey) => {
      if (!hasAttr(attrs, badKey)) return
      const warnId = `${source}:${badKey}->${camelKey}`
      if (warnedKeys.has(warnId)) return
      warnedKeys.add(warnId)
      console.warn(
        `[elementUiPatches] ${source} 检测到非标准写法 "${badKey}"，补丁无法识别。` +
        `请改用 camelCase：${example}（$attrs 键名须为 ${camelKey}，勿用 kebab-case）。`
      )
    })
  })
}

/** 供演示页 / 文档引用的属性说明 */
export const IMAGE_PATCH_ATTR_HINTS = [
  { key: 'fullMode', type: 'Boolean', desc: '预览打开时铺满视口', example: '<el-image fullMode />' },
  { key: 'noInfinite', type: 'Boolean', desc: '禁止首尾循环切换', example: '<el-image noInfinite />' },
  { key: 'viewerRotate', type: 'Number', desc: '预览默认旋转角度', example: '<el-image :viewerRotate="180" />' }
]

export const IMAGE_PATCH_ATTR_WRONG = [
  { wrong: 'full-mode', correct: 'fullMode' },
  { wrong: 'no-infinite', correct: 'noInfinite' },
  { wrong: 'viewer-rotate', correct: 'viewerRotate' }
]
