import Vue from 'vue'
import VueRouter from 'vue-router'

Vue.use(VueRouter)

const routes = [
  {
    path: '/',
    name: 'TileMosaic',
    meta: { title: '分块拼图' },
    component: () => import('../views/TileMosaic.vue')
  },
  {
    path: '/canvas-annotate',
    name: 'CanvasAnnotate',
    meta: { title: 'Canvas 标注' },
    component: () => import('../views/CanvasAnnotate.vue')
  },
  {
    path: '/scatter-perf',
    name: 'ScatterPerfCompare',
    meta: { title: '散点图对比' },
    component: () => import('../views/ScatterPerfCompare.vue')
  },
  {
    path: '/component-showcase',
    name: 'ComponentShowcase',
    meta: { title: '组件封装' },
    component: () => import('../views/ComponentShowcase.vue')
  }
]

const router = new VueRouter({
  mode: 'history',
  base: process.env.BASE_URL,
  routes
})

router.afterEach((to) => {
  const pageTitle = to.meta && to.meta.title
  document.title = pageTitle ? `${pageTitle} · 案例分享示例` : '案例分享示例'
})

export default router
